#include <stdlib.h>

int main() {
    int n, m;
    scanf("%d %d", &n, &m);

    int *dp = (int *)calloc(n + 2, sizeof(int));
    int *s = (int *)calloc(n + 2, sizeof(int));

    dp[n] = 1;
    s[n] = 1;

    for (int i = n - 1; i >= 1; i--) {
        dp[i] = s[i + 1];
