            int h = (n + 1 < (i + 1) * j) ? n + 1 : (i + 1) * j;
            dp[i] = (dp[i] + s[i * j] - s[h]) % m;
        }
        s[i] = (s[i + 1] + dp[i]) % m;
    }

    printf("%d\n", dp[1]);

    free(dp);
    free(s);
    return 0;
}
